async function main() {
  const now = new Date().toISOString()
  const slugs = Object.keys(NEW_CONTENT)
  let enrichedCount = 0

  for (const slug of slugs) {
    const entry = NEW_CONTENT[slug]
    const existing = await prisma.comparison.findUnique({
      where: { slug },
      select: { id: true, content: true, slug: true },
    })

    if (!existing) {
      console.log(`SKIP ${slug} — not found in DB`)
      continue
    }

    const currentContent = existing.content || {}
    const hasEnrichment =
      currentContent &&
      typeof currentContent === 'object' &&
      !Array.isArray(currentContent) &&
      ('expertAnalysis' in currentContent || 'enrichedBy' in currentContent)

    if (hasEnrichment) {
      console.log(`✅ Already enriched: ${slug}`)
      continue
    }

    const updatedContent = {
      ...currentContent,
      expertAnalysis: entry.analysis,
      sources: entry.sources,
      isHumanReviewed: true,
      reviewedBy: 'daniel-rozin',
      reviewedAt: now,
      enrichedBy: 'DAN-2434',
    }

    await prisma.comparison.update({
      where: { slug },
      data: { content: updatedContent },
    })

    // Update FAQs
    await prisma.fAQ.deleteMany({ where: { comparisonId: existing.id } })
    for (const faq of entry.faqs) {
      await prisma.fAQ.create({
        data: {
          question: faq.question,
          answer: faq.answer,
          comparisonId: existing.id,
        },
      })
    }

    const wordCount = entry.analysis.split(/\s+/).length
    console.log(`✓ ${slug} — ${wordCount} words, ${entry.sources.length} sources, ${entry.faqs.length} FAQs`)
    enrichedCount++
  }

  console.log(`\nDone: ${enrichedCount}/${slugs.length} pages enriched`)
  await prisma.$disconnect()
}

main().catch(e => {
  console.error(e)
  process.exit(1)
})
